1. using Microsoft.AspNetCore.Components;
2. using Microsoft.AspNetCore.Identity;
3. using ShipmentTracker.Data;
4. 
5. namespace ShipmentTracker.Components.Account;
6. 
7. internal sealed class IdentityRedirectManager(NavigationManager navigationManager)
8. {
9.     public const string StatusCookieName = "Identity.StatusMessage";
10. 
11.     private static readonly CookieBuilder StatusCookieBuilder = new()
12.     {
13.         SameSite = SameSiteMode.Strict,
14.         HttpOnly = true,
15.         IsEssential = true,
16.         MaxAge = TimeSpan.FromSeconds(5),
17.     };
18. 
19.     public void RedirectTo(string? uri)
20.     {
21.         uri ??= "";
22. 
23.         // Prevent open redirects.
24.         if (!Uri.IsWellFormedUriString(uri, UriKind.Relative))
25.         {
26.             uri = navigationManager.ToBaseRelativePath(uri);
27.         }
28. 
29.         navigationManager.NavigateTo(uri);
30.     }
31. 
32.     public void RedirectTo(string uri, Dictionary<string, object?> queryParameters)
33.     {
34.         var uriWithoutQuery = navigationManager.ToAbsoluteUri(uri).GetLeftPart(UriPartial.Path);
35.         var newUri = navigationManager.GetUriWithQueryParameters(uriWithoutQuery, queryParameters);
36.         RedirectTo(newUri);
37.     }
38. 
39.     public void RedirectToWithStatus(string uri, string message, HttpContext context)
40.     {
41.         context.Response.Cookies.Append(StatusCookieName, message, StatusCookieBuilder.Build(context));
42.         RedirectTo(uri);
43.     }
44. 
45.     private string CurrentPath => navigationManager.ToAbsoluteUri(navigationManager.Uri).GetLeftPart(UriPartial.Path);
46. 
47.     public void RedirectToCurrentPage() => RedirectTo(CurrentPath);
48. 
49.     public void RedirectToCurrentPageWithStatus(string message, HttpContext context)
50.         => RedirectToWithStatus(CurrentPath, message, context);
51. 
52.     public void RedirectToInvalidUser(UserManager<ApplicationUser> userManager, HttpContext context)
53.         => RedirectToWithStatus("Account/InvalidUser", $"Error: Unable to load user with ID '{userManager.GetUserId(context.User)}'.", context);
54. }
55.

