112.             result = await SignInManager.PasskeySignInAsync(Input.Passkey.CredentialJson);
113.         }
114.         else
115.         {
116.             // If doing a password sign-in, validate the form.
117.             if (!editContext.Validate())
118.             {
119.                 return;
120.             }
121. 
122.             // This doesn't count login failures towards account lockout
123.             // To enable password failures to trigger account lockout, set lockoutOnFailure: true
124.             result = await SignInManager.PasswordSignInAsync(Input.Email, Input.Password, Input.RememberMe, lockoutOnFailure: false);
125.         }
