         var user = CreateUser();

         await UserStore.SetUserNameAsync(user, Input.Email, CancellationToken.None);
         await emailStore.SetEmailAsync(user, Input.Email, CancellationToken.None);

         var result = await UserManager.CreateAsync(user);
