                 }
                 else
                 {
                     await SignInManager.SignInAsync(user, isPersistent: false, externalLoginInfo.LoginProvider);
                     RedirectManager.RedirectTo(ReturnUrl);
                 }
             }
         }
         else
         {
             message = $"Error: {string.Join(",", result.Errors.Select(error => error.Description))}";
         }
     }

