 <PageTitle>Manage email</PageTitle>

 <h3>Manage email</h3>

 <StatusMessage Message="@message"/>
 <div class="row">
     <div class="col-xl-6">
         <form @onsubmit="OnSendEmailVerificationAsync" @formname="send-verification" id="send-verification-form" method="post">
             <AntiforgeryToken />
