2. 
3. @using ShipmentTracker.Data
4. @using Microsoft.AspNetCore.Identity
5. @using System.ComponentModel.DataAnnotations
6. @using System.Buffers.Text
7. 
8. @inject UserManager<ApplicationUser> UserManager
9. @inject SignInManager<ApplicationUser> SignInManager
10. @inject IdentityRedirectManager RedirectManager
11. 
12. <PageTitle>Manage your passkeys</PageTitle>
13. 
14. <h3>Manage your passkeys</h3>
15. 
16. <StatusMessage />
17. 
18. @if (currentPasskeys is { Count: > 0 })
19. {
20.     <table class="table">
21.         <tbody>
22.             @foreach (var passkey in currentPasskeys)
23.             {
24.                 <tr>
25.                     <td>@(passkey.Name ?? "Unnamed passkey")</td>
26.                     <td>
27.                         @{
28.                             var credentialId = Base64Url.EncodeToString(passkey.CredentialId);
29.                         }
30.                         <form @formname="@($"update-passkey-{credentialId}")" @onsubmit="UpdatePasskey" method="post">
31.                             <AntiforgeryToken />
32.                             <div>
33.                                 <input type="hidden" name="CredentialId" value="@credentialId" />
34.                                 <button type="submit" name="Action" value="rename" class="btn btn-primary" title="Rename this passkey">Rename</button>
35.                                 <button type="submit" name="Action" value="delete" class="btn btn-danger" title="Remove this passkey from your account">Delete</button>
36.                             </div>
37.                         </form>
38.                     </td>
39.                 </tr>
40.             }
41.         </tbody>
42.     </table>
43. }
44. else
45. {
46.     <p>No passkeys are registered.</p>
47. }
48. 
49. <form @formname="add-passkey" @onsubmit="AddPasskey" method="post">
50.     <AntiforgeryToken />
51.     @if (currentPasskeys is { Count: >= MaxPasskeyCount })
52.     {
53.         <p class="text-danger">You have reached the maximum number of allowed passkeys. Please delete one before adding a new one.</p>
54.     }
55.     else
56.     {
57.         <PasskeySubmit Operation="PasskeyOperation.Create" Name="Input" class="btn btn-primary">Add a new passkey</PasskeySubmit>
58.     }
59. 
60. </form>
61. 
62. @code {
63.     private const int MaxPasskeyCount = 100;
64. 
65.     private ApplicationUser? user;
66.     private IList<UserPasskeyInfo>? currentPasskeys;
67. 
68.     [CascadingParameter]
69.     private HttpContext HttpContext { get; set; } = default!;
70. 
71.     [SupplyParameterFromForm]
72.     private string? Action { get; set; }
73. 
74.     [SupplyParameterFromForm]
75.     private string? CredentialId { get; set; }
76. 
77.     [SupplyParameterFromForm(FormName = "add-passkey")]
78.     private PasskeyInputModel Input { get; set; } = default!;
79. 
80.     protected override async Task OnInitializedAsync()
81.     {
82.         Input ??= new();
83. 
84.         user = await UserManager.GetUserAsync(HttpContext.User);
85.         if (user is null)
86.         {
87.             RedirectManager.RedirectToInvalidUser(UserManager, HttpContext);
88.             return;
89.         }
90.         currentPasskeys = await UserManager.GetPasskeysAsync(user);
91.     }
92. 
93.     private async Task AddPasskey()
94.     {
95.         if (user is null)
96.         {
97.             RedirectManager.RedirectToInvalidUser(UserManager, HttpContext);
98.             return;
99.         }
100. 
101.         if (!string.IsNullOrEmpty(Input.Error))
102.         {
103.             RedirectManager.RedirectToCurrentPageWithStatus($"Error: {Input.Error}", HttpContext);
104.             return;
105.         }
106. 
107.         if (string.IsNullOrEmpty(Input.CredentialJson))
108.         {
109.             RedirectManager.RedirectToCurrentPageWithStatus("Error: The browser did not provide a passkey.", HttpContext);
110.             return;
111.         }
112. 
113.         if (currentPasskeys!.Count >= MaxPasskeyCount)
114.         {
115.             RedirectManager.RedirectToCurrentPageWithStatus($"Error: You have reached the maximum number of allowed passkeys.", HttpContext);
116.             return;
117.         }
118. 
119.         var attestationResult = await SignInManager.PerformPasskeyAttestationAsync(Input.CredentialJson);
120.         if (!attestationResult.Succeeded)
121.         {
122.             RedirectManager.RedirectToCurrentPageWithStatus($"Error: Could not add the passkey: {attestationResult.Failure.Message}", HttpContext);
123.             return;
124.         }
125. 
126.         var addPasskeyResult = await UserManager.AddOrUpdatePasskeyAsync(user, attestationResult.Passkey);
127.         if (!addPasskeyResult.Succeeded)
128.         {
129.             RedirectManager.RedirectToCurrentPageWithStatus("Error: The passkey could not be added to your account.", HttpContext);
130.             return;
131.         }
132. 
133.         // Immediately prompt the user to enter a name for the credential
134.         var credentialIdBase64Url = Base64Url.EncodeToString(attestationResult.Passkey.CredentialId);
135.         RedirectManager.RedirectTo($"Account/Manage/RenamePasskey/{credentialIdBase64Url}");
136.     }
137. 
138.     private async Task UpdatePasskey()
139.     {
140.         switch (Action)
141.         {
142.             case "rename":
143.                 RedirectManager.RedirectTo($"Account/Manage/RenamePasskey/{CredentialId}");
144.                 break;
145.             case "delete":
146.                 await DeletePasskey();
147.                 break;
148.             default:
149.                 RedirectManager.RedirectToCurrentPageWithStatus($"Error: Unknown action '{Action}'.", HttpContext);
150.                 break;
151.         }
152.     }
153. 
154.     private async Task DeletePasskey()
155.     {
156.         if (user is null)
157.         {
158.             RedirectManager.RedirectToInvalidUser(UserManager, HttpContext);
159.             return;
160.         }
161. 
162.         byte[] credentialId;
