namespace ShipmentTracker.Client.Models;

public enum ShipmentStatus
{
    Pending,
    PickedUp,
    InTransit,
    OutForDelivery,
    Delivered,
    Cancelled
}

public class ShipmentDto
{
    public int Id { get; set; }
    public string TrackingNumber { get; set; } = string.Empty;
    public string Origin { get; set; } = string.Empty;
    public string Destination { get; set; } = string.Empty;
    public ShipmentStatus Status { get; set; }
    public DateTime CreatedAt { get; set; }
    public DateTime? EstimatedDelivery { get; set; }
    public DateTime? ActualDelivery { get; set; }
    public string RecipientName { get; set; } = string.Empty;
    public string Description { get; set; } = string.Empty;
    public double WeightKg { get; set; }
}

public class UpdateShipmentStatusRequest
{
    public ShipmentStatus NewStatus { get; set; }
}

public class TrackingResult
{
    public bool Found { get; set; }
    public ShipmentDto? Shipment { get; set; }
    public string? ErrorMessage { get; set; }
}

using System.ComponentModel.DataAnnotations;

namespace ShipmentTracker.Data;

public enum ShipmentStatus
{
    Pending,
    PickedUp,
    InTransit,
    OutForDelivery,
    Delivered,
    Cancelled
}

public class Shipment
{
    public int Id { get; set; }

    [Required, MaxLength(20)]
    public string TrackingNumber { get; set; } = string.Empty;

    [Required, MaxLength(200)]
    public string Origin { get; set; } = string.Empty;

    [Required, MaxLength(200)]
    public string Destination { get; set; } = string.Empty;

    public ShipmentStatus Status { get; set; }

    public DateTime CreatedAt { get; set; } = DateTime.UtcNow;

    public DateTime? EstimatedDelivery { get; set; }

    public DateTime? ActualDelivery { get; set; }

    [Required, MaxLength(150)]
    public string RecipientName { get; set; } = string.Empty;

    [MaxLength(500)]
    public string Description { get; set; } = string.Empty;

    public double WeightKg { get; set; }

    // The customer (ApplicationUser) who owns this shipment
    [Required]
    public string CustomerId { get; set; } = string.Empty;
    public ApplicationUser Customer { get; set; } = null!;
}

@page "/shipments"
@rendermode InteractiveAuto
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@attribute [Authorize(Roles = "Dispatcher")]
@inject HttpClient Http

<PageTitle>Dispatcher Dashboard</PageTitle>

<h1>Shipment Dashboard</h1>

<div class="row mb-3">
    <div class="col-md-4">
        <input type="text" class="form-control" placeholder="Filter by tracking # or destination..."
               @bind="filterText" @bind:event="oninput" />
    </div>
    <div class="col-md-3">
        <select class="form-select" @bind="statusFilter">
            <option value="">All Statuses</option>
            @foreach (var s in Enum.GetValues<ShipmentStatus>())
            {
                <option value="@s">@s</option>
            }
        </select>
    </div>
    <div class="col-md-2">
        <button class="btn btn-primary w-100" @onclick="LoadShipments">
            <span class="bi bi-arrow-clockwise" aria-hidden="true"></span> Refresh
        </button>
    </div>
</div>

@if (loading)
{
    <p><em>Loading shipments...</em></p>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger">@errorMessage</div>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead class="table-dark">
                <tr>
                    <th>Tracking #</th>
                    <th>Origin</th>
                    <th>Destination</th>
                    <th>Recipient</th>
                    <th>Weight (kg)</th>
                    <th>Status</th>
                    <th>Est. Delivery</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var shipment in FilteredShipments)
                {
                    <tr>
                        <td><strong>@shipment.TrackingNumber</strong></td>
                        <td>@shipment.Origin</td>
                        <td>@shipment.Destination</td>
                        <td>@shipment.RecipientName</td>
                        <td>@shipment.WeightKg.ToString("F1")</td>
                        <td>
                            <span class="badge @GetStatusBadgeClass(shipment.Status)">
                                @shipment.Status
                            </span>
                        </td>
                        <td>@shipment.EstimatedDelivery?.ToString("MMM dd, yyyy")</td>
                        <td>
                            @if (shipment.Status != ShipmentStatus.Delivered && shipment.Status != ShipmentStatus.Cancelled)
                            {
                                <div class="btn-group btn-group-sm">
                                    <select class="form-select form-select-sm" style="width: auto"
                                            @onchange="e => UpdateStatus(shipment, e)">
                                        <option value="" disabled selected>Change...</option>
                                        @foreach (var s in GetAllowedTransitions(shipment.Status))
                                        {
                                            <option value="@((int)s)">@s</option>
                                        }
                                    </select>
                                </div>
                            }
                            else
                            {
                                <span class="text-muted">—</span>
                            }
                        </td>
                    </tr>
                }
            </tbody>
        </table>
    </div>

    <p class="text-muted">Showing @FilteredShipments.Count() of @shipments.Count shipments</p>
}

@code {
    private List<ShipmentDto> shipments = new();
    private bool loading = true;
    private string? errorMessage;
    private string filterText = "";
    private string statusFilter = "";

    private IEnumerable<ShipmentDto> FilteredShipments => shipments.Where(s =>
    {
        if (!string.IsNullOrWhiteSpace(statusFilter)
            && Enum.TryParse<ShipmentStatus>(statusFilter, out var sf)
            && s.Status != sf)
            return false;

        if (!string.IsNullOrWhiteSpace(filterText))
        {
            var term = filterText.Trim();
            return s.TrackingNumber.Contains(term, StringComparison.OrdinalIgnoreCase)
                || s.Destination.Contains(term, StringComparison.OrdinalIgnoreCase)
                || s.RecipientName.Contains(term, StringComparison.OrdinalIgnoreCase);
        }

        return true;
    });

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        loading = true;
        errorMessage = null;
        try
        {
            shipments = await Http.GetFromJsonAsync<List<ShipmentDto>>("api/shipments") ?? new();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load shipments: {ex.Message}";
        }
        finally
        {
            loading = false;
        }
    }

    private async Task UpdateStatus(ShipmentDto shipment, ChangeEventArgs e)
    {
        if (e.Value is not string val || !int.TryParse(val, out var statusInt))
            return;

        var newStatus = (ShipmentStatus)statusInt;
        try
        {
            var response = await Http.PutAsJsonAsync(
                $"api/shipments/{shipment.Id}/status",
                new UpdateShipmentStatusRequest { NewStatus = newStatus });

            if (response.IsSuccessStatusCode)
            {
                shipment.Status = newStatus;
                if (newStatus == ShipmentStatus.Delivered)
                    shipment.ActualDelivery = DateTime.UtcNow;
            }
            else
            {
                errorMessage = $"Failed to update shipment {shipment.TrackingNumber}";
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Error: {ex.Message}";
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };

    private static ShipmentStatus[] GetAllowedTransitions(ShipmentStatus current) => current switch
    {
        ShipmentStatus.Pending => [ShipmentStatus.PickedUp, ShipmentStatus.Cancelled],
        ShipmentStatus.PickedUp => [ShipmentStatus.InTransit, ShipmentStatus.Cancelled],
        ShipmentStatus.InTransit => [ShipmentStatus.OutForDelivery, ShipmentStatus.Cancelled],
        ShipmentStatus.OutForDelivery => [ShipmentStatus.Delivered, ShipmentStatus.Cancelled],
        _ => []
    };
}

@page "/my-shipments"
@rendermode InteractiveAuto
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@attribute [Authorize(Roles = "Customer")]
@inject HttpClient Http

<PageTitle>My Shipments</PageTitle>

<h1>My Shipments</h1>
<p class="text-muted">Track your packages and view estimated delivery dates.</p>

<div class="row mb-3">
    <div class="col-md-4">
        <input type="text" class="form-control" placeholder="Search by tracking # or destination..."
               @bind="searchText" @bind:event="oninput" />
    </div>
</div>

@if (loading)
{
    <p><em>Loading your shipments...</em></p>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger">@errorMessage</div>
}
else if (!shipments.Any())
{
    <div class="alert alert-info">You have no shipments yet.</div>
}
else
{
    <div class="row">
        @foreach (var shipment in FilteredShipments)
        {
            <div class="col-md-6 col-lg-4 mb-3">
                <div class="card h-100">
                    <div class="card-header d-flex justify-content-between align-items-center">
                        <strong>@shipment.TrackingNumber</strong>
                        <span class="badge @GetStatusBadgeClass(shipment.Status)">@shipment.Status</span>
                    </div>
                    <div class="card-body">
                        <p class="mb-1"><strong>From:</strong> @shipment.Origin</p>
                        <p class="mb-1"><strong>To:</strong> @shipment.Destination</p>
                        <p class="mb-1"><strong>Description:</strong> @shipment.Description</p>
                        <p class="mb-1"><strong>Weight:</strong> @shipment.WeightKg.ToString("F1") kg</p>
                        <hr />
                        @if (shipment.Status == ShipmentStatus.Delivered)
                        {
                            <p class="mb-0 text-success">
                                <strong>Delivered:</strong> @shipment.ActualDelivery?.ToString("MMM dd, yyyy 'at' h:mm tt")
                            </p>
                        }
                        else if (shipment.Status == ShipmentStatus.Cancelled)
                        {
                            <p class="mb-0 text-danger"><strong>This shipment has been cancelled.</strong></p>
                        }
                        else
                        {
                            <p class="mb-0">
                                <strong>Estimated Delivery:</strong>
                                @if (shipment.EstimatedDelivery.HasValue)
                                {
                                    var daysLeft = (shipment.EstimatedDelivery.Value - DateTime.UtcNow).Days;
                                    <span>@shipment.EstimatedDelivery.Value.ToString("MMM dd, yyyy")</span>
                                    @if (daysLeft > 0)
                                    {
                                        <span class="text-muted"> (@daysLeft day@(daysLeft != 1 ? "s" : "") away)</span>
                                    }
                                    else if (daysLeft == 0)
                                    {
                                        <span class="text-warning"> (arriving today)</span>
                                    }
                                    else
                                    {
                                        <span class="text-danger"> (delayed)</span>
                                    }
                                }
                                else
                                {
                                    <span class="text-muted">TBD</span>
                                }
                            </p>
                        }
                    </div>
                    <div class="card-footer">
                        <small class="text-muted">Shipped: @shipment.CreatedAt.ToString("MMM dd, yyyy")</small>
                    </div>
                </div>
            </div>
        }
    </div>

    <p class="text-muted mt-2">Showing @FilteredShipments.Count() of @shipments.Count shipments</p>
}

@code {
    private List<ShipmentDto> shipments = new();
    private bool loading = true;
    private string? errorMessage;
    private string searchText = "";

    private IEnumerable<ShipmentDto> FilteredShipments => shipments.Where(s =>
    {
        if (string.IsNullOrWhiteSpace(searchText)) return true;
        var term = searchText.Trim();
        return s.TrackingNumber.Contains(term, StringComparison.OrdinalIgnoreCase)
            || s.Destination.Contains(term, StringComparison.OrdinalIgnoreCase);
    });

    protected override async Task OnInitializedAsync()
    {
        try
        {
            shipments = await Http.GetFromJsonAsync<List<ShipmentDto>>("api/shipments/mine") ?? new();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load shipments: {ex.Message}";
        }
        finally
        {
            loading = false;
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };
}

@page "/track"
@rendermode InteractiveAuto
@using ShipmentTracker.Client.Models
@inject HttpClient Http

<PageTitle>Track a Shipment</PageTitle>

<h1>Track Your Shipment</h1>
<p class="text-muted">Enter your tracking number to check the status of your shipment.</p>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
