@code {
    private List<ShipmentDto> shipments = new();
    private bool loading = true;
    private string? errorMessage;
    private string filterText = "";
    private string statusFilter = "";

    private IEnumerable<ShipmentDto> FilteredShipments => shipments.Where(s =>
    {
        if (!string.IsNullOrWhiteSpace(statusFilter)
            && Enum.TryParse<ShipmentStatus>(statusFilter, out var sf)
            && s.Status != sf)
            return false;

        if (!string.IsNullOrWhiteSpace(filterText))
        {
            var term = filterText.Trim();
            return s.TrackingNumber.Contains(term, StringComparison.OrdinalIgnoreCase)
                || s.Destination.Contains(term, StringComparison.OrdinalIgnoreCase)
                || s.RecipientName.Contains(term, StringComparison.OrdinalIgnoreCase);
        }

        return true;
    });

    protected override async Task OnInitializedAsync()
    {
        await LoadShipments();
    }

    private async Task LoadShipments()
    {
        loading = true;
        errorMessage = null;
        try
        {
            shipments = await Http.GetFromJsonAsync<List<ShipmentDto>>("api/shipments") ?? new();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load shipments: {ex.Message}";
        }
        finally
        {
            loading = false;
        }
    }

    private async Task UpdateStatus(ShipmentDto shipment, ChangeEventArgs e)
    {
        if (e.Value is not string val || !int.TryParse(val, out var statusInt))
            return;

        var newStatus = (ShipmentStatus)statusInt;
        try
        {
            var response = await Http.PutAsJsonAsync(
                $"api/shipments/{shipment.Id}/status",
                new UpdateShipmentStatusRequest { NewStatus = newStatus });

            if (response.IsSuccessStatusCode)
            {
                shipment.Status = newStatus;
                if (newStatus == ShipmentStatus.Delivered)
                    shipment.ActualDelivery = DateTime.UtcNow;
            }
            else
            {
                errorMessage = $"Failed to update shipment {shipment.TrackingNumber}";
            }
        }
        catch (Exception ex)
        {
            errorMessage = $"Error: {ex.Message}";
        }
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };

    private static ShipmentStatus[] GetAllowedTransitions(ShipmentStatus current) => current switch
    {
        ShipmentStatus.Pending => [ShipmentStatus.PickedUp, ShipmentStatus.Cancelled],
        ShipmentStatus.PickedUp => [ShipmentStatus.InTransit, ShipmentStatus.Cancelled],
        ShipmentStatus.InTransit => [ShipmentStatus.OutForDelivery, ShipmentStatus.Cancelled],
        ShipmentStatus.OutForDelivery => [ShipmentStatus.Delivered, ShipmentStatus.Cancelled],
        _ => []
    };
}
"}

