                <div class="row mb-2">
                    <div class="col-sm-4 fw-bold">To</div>
                    <div class="col-sm-8">@s.Destination</div>
                </div>
                <div class="row mb-2">
                    <div class="col-sm-4 fw-bold">Recipient</div>
                    <div class="col-sm-8">@s.RecipientName</div>
                </div>
                <div class="row mb-2">
                    <div class="col-sm-4 fw-bold">Description</div>
                    <div class="col-sm-8">@s.Description</div>
                </div>
                <div class="row mb-2">
                    <div class="col-sm-4 fw-bold">Weight</div>
                    <div class="col-sm-8">@s.WeightKg.ToString("F1") kg</div>
                </div>
                <div class="row mb-2">
                    <div class="col-sm-4 fw-bold">Shipped On</div>
                    <div class="col-sm-8">@s.CreatedAt.ToString("MMM dd, yyyy")</div>
                </div>
                <hr />
                @if (s.Status == ShipmentStatus.Delivered)
                {
                    <div class="alert alert-success mb-0">
                        Delivered on @s.ActualDelivery?.ToString("MMM dd, yyyy 'at' h:mm tt")
                    </div>
                }
                else if (s.Status == ShipmentStatus.Cancelled)
                {
                    <div class="alert alert-danger mb-0">This shipment has been cancelled.</div>
                }
                else
                {
                    <div class="row">
                        <div class="col-sm-4 fw-bold">Estimated Delivery</div>
                        <div class="col-sm-8">
                            @if (s.EstimatedDelivery.HasValue)
                            {
                                @s.EstimatedDelivery.Value.ToString("MMM dd, yyyy")
                            }
                            else
                            {
                                <span class="text-muted">To be determined</span>
                            }
                        </div>
                    </div>

                    <!-- Progress indicator -->
                    <div class="mt-3">
                        @{ var steps = new[] { ShipmentStatus.Pending, ShipmentStatus.PickedUp, ShipmentStatus.InTransit, ShipmentStatus.OutForDelivery, ShipmentStatus.Delivered }; }
                        <div class="d-flex justify-content-between">
                            @foreach (var step in steps)
                            {
                                var isActive = (int)s.Status >= (int)step;
                                <div class="text-center" style="flex: 1;">
                                    <div class="rounded-circle mx-auto @(isActive ? "bg-primary" : "bg-secondary")"
                                         style="width: 20px; height: 20px;"></div>
                                    <small class="@(isActive ? "fw-bold" : "text-muted")">@step</small>
                                </div>
                            }
                        </div>
                    </div>
                }
            </div>
        </div>
    }
}

@code {
    private string trackingNumber = "";
    private bool searching;
    private TrackingResult? result;

    private async Task Search()
    {
        if (string.IsNullOrWhiteSpace(trackingNumber)) return;

        searching = true;
        result = null;
        try
        {
            var response = await Http.GetAsync($"api/shipments/track/{Uri.EscapeDataString(trackingNumber.Trim())}");
            if (response.IsSuccessStatusCode)
            {
                var shipment = await response.Content.ReadFromJsonAsync<ShipmentDto>();
                result = new TrackingResult { Found = true, Shipment = shipment };
            }
            else
            {
                result = new TrackingResult { Found = false, ErrorMessage = "No shipment found with that tracking number." };
            }
        }
        catch (Exception ex)
        {
            result = new TrackingResult { Found = false, ErrorMessage = $"Error: {ex.Message}" };
        }
        finally
        {
            searching = false;
        }
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter")
            await Search();
    }

    private static string GetStatusBadgeClass(ShipmentStatus status) => status switch
    {
        ShipmentStatus.Pending => "bg-secondary",
        ShipmentStatus.PickedUp => "bg-info",
        ShipmentStatus.InTransit => "bg-primary",
        ShipmentStatus.OutForDelivery => "bg-warning text-dark",
        ShipmentStatus.Delivered => "bg-success",
        ShipmentStatus.Cancelled => "bg-danger",
        _ => "bg-secondary"
    };
}
"}

