@page "/shipments"
@rendermode InteractiveAuto
@using Microsoft.AspNetCore.Authorization
@using ShipmentTracker.Client.Models
@attribute [Authorize(Roles = "Dispatcher")]
@inject HttpClient Http

<PageTitle>Dispatcher Dashboard</PageTitle>

<h1>Shipment Dashboard</h1>

<div class="row mb-3">
    <div class="col-md-4">
        <input type="text" class="form-control" placeholder="Filter by tracking # or destination..."
               @bind="filterText" @bind:event="oninput" />
    </div>
    <div class="col-md-3">
        <select class="form-select" @bind="statusFilter">
            <option value="">All Statuses</option>
            @foreach (var s in Enum.GetValues<ShipmentStatus>())
            {
                <option value="@s">@s</option>
            }
        </select>
    </div>
    <div class="col-md-2">
        <button class="btn btn-primary w-100" @onclick="LoadShipments">
            <span class="bi bi-arrow-clockwise" aria-hidden="true"></span> Refresh
        </button>
    </div>
</div>

@if (loading)
{
    <p><em>Loading shipments...</em></p>
}
else if (errorMessage is not null)
{
    <div class="alert alert-danger">@errorMessage</div>
}
else
{
    <div class="table-responsive">
        <table class="table table-striped table-hover">
            <thead class="table-dark">
                <tr>
                    <th>Tracking #</th>
                    <th>Origin</th>
                    <th>Destination</th>
                    <th>Recipient</th>
                    <th>Weight (kg)</th>
                    <th>Status</th>
                    <th>Est. Delivery</th>
                    <th>Actions</th>
                </tr>
            </thead>
            <tbody>
                @foreach (var shipment in FilteredShipments)
                {
                    <tr>
                        <td><strong>@shipment.TrackingNumber</strong></td>
                        <td>@shipment.Origin</td>
                        <td>@shipment.Destination</td>
                        <td>@shipment.RecipientName</td>
                        <td>@shipment.WeightKg.ToString("F1")</td>
                        <td>
                            <span class="badge @GetStatusBadgeClass(shipment.Status)">
                                @shipment.Status
                            </span>
                        </td>
                        <td>@shipment.EstimatedDelivery?.ToString("MMM dd, yyyy")</td>
                        <td>
                            @if (shipment.Status != ShipmentStatus.Delivered && shipment.Status != ShipmentStatus.Cancelled)
                            {
                                <div class="btn-group btn-group-sm">
                                    <select class="form-select form-select-sm" style="width: auto"
                                            @onchange="e => UpdateStatus(shipment, e)">
                                        <option value="" disabled selected>Change...</option>
                                        @foreach (var s in GetAllowedTransitions(shipment.Status))
                                        {
                                            <option value="@((int)s)">@s</option>
                                        }
                                    </select>
                                </div>
                            }
                            else
                            {
                                <span class="text-muted">—</span>
                            }
                        </td>
                    </tr>
                }
