+                <strong>@s.TrackingNumber</strong>
+                <span class="badge @GetStatusBadgeClass(s.Status)">@s.Status</span>
+            </div>
+            <div class="card-body">
+                <div class="row mb-2">
+                    <div class="col-sm-4 fw-bold">From</div>
+                    <div class="col-sm-8">@s.Origin</div>
+                </div>
+                <div class="row mb-2">
+                    <div class="col-sm-4 fw-bold">To</div>
+                    <div class="col-sm-8">@s.Destination</div>
+                </div>
+                <div class="row mb-2">
+                    <div class="col-sm-4 fw-bold">Recipient</div>
+                    <div class="col-sm-8">@s.RecipientName</div>
+                </div>
