+                    <div class="col-sm-4 fw-bold">Weight</div>
+                    <div class="col-sm-8">@s.WeightKg.ToString("F1") kg</div>
+                </div>
+                <div class="row mb-2">
+                    <div class="col-sm-4 fw-bold">Shipped On</div>
+                    <div class="col-sm-8">@s.CreatedAt.ToString("MMM dd, yyyy")</div>
+                </div>
+                <hr />
+                @if (s.Status == ShipmentStatus.Delivered)
+                {
+                    <div class="alert alert-success mb-0">
+                        Delivered on @s.ActualDelivery?.ToString("MMM dd, yyyy 'at' h:mm tt")
+                    </div>
+                }
+                else if (s.Status == ShipmentStatus.Cancelled)
+                {
+                    <div class="alert alert-danger mb-0">This shipment has been cancelled.</div>
+                }
+                else
+                {
+                    <div class="row">
+                        <div class="col-sm-4 fw-bold">Estimated Delivery</div>
+                        <div class="col-sm-8">
+                            @if (s.EstimatedDelivery.HasValue)
+                            {
+                                @s.EstimatedDelivery.Value.ToString("MMM dd, yyyy")
+                            }
+                            else
+                            {
+                                <span class="text-muted">To be determined</span>
+                            }
+                        </div>
+                    </div>
+
+                    <!-- Progress indicator -->
+                    <div class="mt-3">
+                        @{ var steps = new[] { ShipmentStatus.Pending, ShipmentStatus.PickedUp, ShipmentStatus.InTransit, ShipmentStatus.OutForDelivery, ShipmentStatus.Delivered }; }
+                        <div class="d-flex justify-content-between">
+                            @foreach (var step in steps)
+                            {
+                                var isActive = (int)s.Status >= (int)step;
+                                <div class="text-center" style="flex: 1;">
+                                    <div class="rounded-circle mx-auto @(isActive ? "bg-primary" : "bg-secondary")"
+                                         style="width: 20px; height: 20px;"></div>
+                                    <small class="@(isActive ? "fw-bold" : "text-muted")">@step</small>
+                                </div>
+                            }
+                        </div>
+                    </div>
+                }
+            </div>
+        </div>
+    }
+}
