+                .OrderByDescending(s => s.CreatedAt)
+                .Select(s => ToDto(s))
+                .ToListAsync();
+
+            return Results.Ok(shipments);
+        }).RequireAuthorization(policy => policy.RequireRole("Customer"));
+
+        // GET track by tracking number (public)
+        group.MapGet("/track/{trackingNumber}", async (string trackingNumber, ApplicationDbContext db) =>
+        {
+            var shipment = await db.Shipments
+                .FirstOrDefaultAsync(s => s.TrackingNumber == trackingNumber);
+
+            if (shipment is null) return Results.NotFound();
+
+            return Results.Ok(ToDto(shipment));
+        });
+
+        // PUT update shipment status (dispatchers only)
+        group.MapPut("/{id:int}/status", async (int id, UpdateShipmentStatusRequest request, ApplicationDbContext db) =>
+        {
+            var shipment = await db.Shipments.FindAsync(id);
+            if (shipment is null) return Results.NotFound();
+
+            shipment.Status = (Data.ShipmentStatus)(int)request.NewStatus;
+
+            if (request.NewStatus == Client.Models.ShipmentStatus.Delivered)
+                shipment.ActualDelivery = DateTime.UtcNow;
+
+            await db.SaveChangesAsync();
+            return Results.Ok(ToDto(shipment));
+        }).RequireAuthorization(policy => policy.RequireRole("Dispatcher"));
+    }
+
+    private static ShipmentDto ToDto(Shipment s) => new()
+    {
+        Id = s.Id,
+        TrackingNumber = s.TrackingNumber,
+        Origin = s.Origin,
+        Destination = s.Destination,
+        Status = (Client.Models.ShipmentStatus)(int)s.Status,
+        CreatedAt = s.CreatedAt,
+        EstimatedDelivery = s.EstimatedDelivery,
+        ActualDelivery = s.ActualDelivery,
+        RecipientName = s.RecipientName,
+        Description = s.Description,
+        WeightKg = s.WeightKg
+    };
+}
+

